// Load manifest (inline; sync with n8n/secrets.manifest.yml). Validate schema.
const manifest = {
  version: '1.0',
  secrets: [
    { name: 'N8N_API_KEY', source: 'ENV', required: true },
    { name: 'N8N_ENCRYPTION_KEY', source: 'ENV', required: true },
    { name: 'SUPABASE_SERVICE_ROLE_KEY', source: 'ENV', required: true },
    { name: 'ANTHROPIC_API_KEY', source: 'ENV', required: true },
    { name: 'OPENAI_API_KEY', source: 'ENV', required: true },
    { name: 'MONDAY_API_TOKEN', source: 'ENV', required: false },
    { name: 'CLOUDFLARE_API_TOKEN', source: 'ENV', required: false },
    { name: 'COMMANDER_WEBHOOK_TOKEN', source: 'ENV', required: true },
    { name: 'VAULT_MASTER_KEY', source: 'ENV', required: false },
    { name: 'FIRECRAWL_API_KEY', source: 'ENV', required: false },
    { name: 'GRAFANA_PASSWORD', source: 'ENV', required: false }
  ],
  n8n_credentials: [
    { type: 'supabaseApi', name: 'Prod - Supabase Service Role' },
    { type: 'anthropicApi', name: 'Prod - Anthropic Claude' },
    { type: 'anthropicApi', name: 'AnthropicApi' },
    { type: 'openAiApi', name: 'Prod - OpenAI' },
    { type: 'gmailOAuth2', name: 'Prod - Gmail' },
    { type: 'googleSheetsOAuth2Api', name: 'Prod - Google Sheets' },
    { type: 'mondayComApi', name: 'Prod - Monday.com' }
  ]
};
const schemaOk = manifest.version && Array.isArray(manifest.secrets) && manifest.secrets.every(s => s.name && s.source && s.required !== undefined);
if (!schemaOk) throw new Error('Manifest schema invalid');
return [{ json: manifest }];

// Check ENV secrets by inspecting process.env.
// NEVER output actual values — only presence.
const manifest = $input.first().json;
const results = { ok: true, missing: [], present: [], warnings: [] };

for (const secret of manifest.secrets) {
  if (secret.source === 'ENV') {
    const val = process.env[secret.name];
    if (!val || val.startsWith('paste-your-')) {
      if (secret.required) {
        results.missing.push(secret.name);
        results.ok = false;
      } else {
        results.warnings.push(`${secret.name} (optional) not set`);
      }
    } else {
      results.present.push(secret.name);
    }
  }
}

results.env_checked = manifest.secrets.filter(s => s.source === 'ENV').length;
return [{ json: results }];

// Check VAULT_REF secrets via vault adapter (existence only).
const vaultBase = process.env.VAULT_BASE_URL || 'http://localhost:4000';
const envResults = $input.first().json;
const manifest = $('Load Manifest').first().json;
const vaultNames = (manifest.secrets || []).filter(s => s.source === 'VAULT_REF').map(s => s.name);
if (vaultNames.length === 0) vaultNames.push('VAULT_MASTER_KEY');
const vaultResults = { vault_checked: 0, vault_present: [], vault_missing: [] };
for (const name of vaultNames) {
  if (envResults.present && envResults.present.includes(name)) continue;
  try {
    const resp = await fetch(`${vaultBase}/secret/${name}`);
    vaultResults.vault_checked++;
    if (resp.ok) vaultResults.vault_present.push(name);
    else vaultResults.vault_missing.push(name);
  } catch (e) {
    vaultResults.vault_missing.push(name);
    envResults.warnings = envResults.warnings || [];
    envResults.warnings.push(`Vault unreachable for ${name}: ${e.message}`);
  }
}
return [{ json: { ...envResults, ...vaultResults } }];

// Check n8n credentials via the n8n API (existence only, names only).
const report = $input.first().json;
const manifest = $('Load Manifest').first().json;
const n8nBase = (process.env.N8N_BASE_URL || process.env.N8N_URL || '').replace(/\/$/, '');
const n8nApiKey = process.env.N8N_API_KEY;
const credResults = { creds_checked: 0, creds_present: [], creds_missing: [] };
const credList = manifest.n8n_credentials || [];

if (n8nBase && n8nApiKey) {
  try {
    const resp = await fetch(`${n8nBase}/api/v1/credentials`, {
      headers: { 'X-N8N-API-KEY': n8nApiKey, 'Accept': 'application/json' }
    });
    if (resp.ok) {
      const data = await resp.json();
      const existingNames = (data.data || []).map(c => c.name);
      for (const cred of credList) {
        credResults.creds_checked++;
        if (existingNames.includes(cred.name)) {
          credResults.creds_present.push(cred.name);
        } else {
          credResults.creds_missing.push(cred.name);
        }
      }
    } else {
      report.warnings.push(`n8n API returned ${resp.status}`);
    }
  } catch (e) {
    report.warnings.push(`n8n API unreachable: ${e.message}`);
  }
} else {
  report.warnings.push('N8N_BASE_URL or N8N_API_KEY not set — skipping credential check');
}

if (credResults.creds_missing.length > 0) report.ok = false;

return [{ json: { ...report, ...credResults } }];

// Build final report. Never include secret values. Gate 4: ok, missing[], warnings[], checked_at, version_sha.
const r = $input.first().json;
const manifest = $('Load Manifest').first().json;
const allMissing = [...(r.missing || []), ...(r.vault_missing || []), ...(r.creds_missing || [])];
const report = {
  ok: r.ok,
  missing: allMissing,
  warnings: r.warnings || [],
  checked_at: new Date().toISOString(),
  version_sha: manifest.version || '1.0',
  summary: r.ok ? 'All required secrets and credentials are present.' : 'Missing secrets or credentials detected.',
  env: { checked: r.env_checked || 0, present: r.present || [], missing: r.missing || [] },
  vault: { checked: r.vault_checked || 0, present: r.vault_present || [], missing: r.vault_missing || [] },
  n8n_credentials: { checked: r.creds_checked || 0, present: r.creds_present || [], missing: r.creds_missing || [] },
  all_missing: allMissing
};
return [{ json: report }];
